1	// MHPCO Claim Office - Insurance Policy Management System
2	
3	interface Item {
4	  type: string;
5	  cursed?: boolean;
6	}
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  component: 30,
14	  rune: 30,
15	};
16	
17	const PROCESSING_FEES: Record<number, number> = {
18	  0: 0,
19	  1: 5,
20	  2: 10,
21	  3: 20,
22	};
23	
24	const calculateBasePremium = (items: Item[]): number => {
25	  return items.reduce((sum, item) => {
26	    const basePremium = BASE_PREMIUMS[item.type] ?? 0;
27	    const cursedSurcharge = item.cursed ? basePremium * 0.5 : 0;
28	    return sum + basePremium + cursedSurcharge;
29	  }, 0);
30	};
31	
32	const getProcessingFee = (itemCount: number): number => {
33	  return PROCESSING_FEES[itemCount] ?? 5;
34	};
35	
36	export function quote(items: Item[]): number {
37	  if (items.length === 0) return 0;
38	
39	  // Building block rule: exactly 3 identical components get 60 G base premium
40	  if (items.length === 3 && items.every(item => item.type === "component")) {
41	    return 60;
42	  }
43	
44	  return calculateBasePremium(items) + getProcessingFee(items.length);
45	}
46	
47	export function claim(): number {
48	  throw new Error("Not implemented");
49	}
50	

